+                IllegalArgumentException.class,
+                () -> ModuleLink.write(links, buffer, null));
+        assertTrue(err.getMessage().contains("buffer capacity"));
+    }
+
+    @Test
+    public void writeBuffer_multiplePackagesWithResources() {
